{"type":"freeform","cover":{"titleText":"","subTitleText":"","presenterText":"","dateText":"","logos":[]},"section":{"sectionText":"","smallerSectionText":""},"freeform":{"content":[[{"type":"text","stretch":true,"fillArea":true,"textSize":1,"textBackground":"grey","placeholderInvisible":false,"useFigureAdditionalScale":false,"figureAdditionalScale":1,"span":3,"markdown":"At the national level, the overall DQA score improved steadily, reaching 85% in 2025.

